import { getURLSafeHostname } from "./Hostname.js";
/**
 * Identifies another endpoint (similar to the new WhatWG URL API "origin" property)
 */
export class Origin {
    protocol;
    hostname;
    port;
    constructor(protocol, hostname, port) {
        this.protocol = protocol;
        this.hostname = hostname;
        this.port = port;
    }
    toString() {
        return `${this.protocol}//${getURLSafeHostname(this.hostname)}:${this.port}`;
    }
    static fromUrl(url) {
        return new Origin(url.protocol, url.hostname, +url.port);
    }
    static parse(origin) {
        return Origin.fromUrl(new URL(origin));
    }
}
